#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int *arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        int mid = (n + 1) / 2;
        for (int i = 0; i < mid; ++i) {
            if (i) printf(" ");
            printf("%d", arr[i]);
        }
        printf("\n");
        for (int i = mid; i < n; ++i) {
            if (i > mid) printf(" ");
            printf("%d", arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

